//vip.opstream11.com/20220327/5835_e86d595b/index.m3u8"},{"name":"104","slug":"104","filename":"Ngày Mới Bắt Đầu - Bepanaah - Tập 104","link_embed":"https://vip.opstream11.com/share/d1e39c9bda5c80ac3d8ea9d658163967","link_m3u8":"https://vip.opstream11.com/20220327/5837_fa4d8591/index.m3u8"},{"name":"105","slug":"105","filename":"Ngày Mới Bắt Đầu - Bepanaah - Tập 105","link_embed":"https://vip.opstream11.com/share/a91bc76c2a6302e573badedcbf57bf7a","link_m3u8":"https://vip.opstream11.com/20220327/5838_92677267/index.m3u8"},{"name":"106","slug":"106","filename":"Ngày Mới Bắt Đầu - Bepanaah - Tập 106","link_embed":"https://vip.opstream11.com/share/6fd9a99a5abed788d9afc9d52d54e91b","link_m3u8":"https://vip.opstream11.com/20220327/5836_22c5289a/index.m3u8"}]}],"time":"45 phút/tập","description":"<p>Vợ của Aditya (Pooja) cùng chồng của Zoya (Yash) ngoại tình và bị chết vì gặp tai nạn giao thông khi họ đang trên đường đi du lịch cùng nhau. Khi phát hiện thêm việc Pooja đã mang thai với Yash, Aditya và Zoya đã đau buồn và sốc tột độ vì vừa mới ngày hôm qua hai người đó vẫn ngọt ngào hạnh phúc với họ. Zoya đã tự vẫn nhưng Aditya đã cứu được cô. Ngoài nỗi đau đang chịu thì Aditya và Zoya lại bị cảnh sát nghi ngờ là chủ mưu vụ tai nạn kia nên họ phải chứng minh sự vô tội của mình bằng mọi cách. May mắn là cuốn nhật ký của Pooja đã làm sáng tỏ được mọi chuyện. Aditya quyết định rời khỏi Ấn Độ đến Paris sống 1 thời gian và Zoya cũng bị cuốn theo công ty sắp phá sản của cô. Aditya trở lại Ấn Độ với tâm tính trầm lắng, đau buồn như trước và anh gặp lại Zoya – đã trở thành một phụ nữ tự tin và quyết đoán. Họ bắt đầu dành thời gian bên nhau và tình cảm của Aditya với Zoya ngày càng nhiều. Lúc đầu, Aditya phớt lờ việc Arshad theo đuổi Zoya nhưng sự việc đi quá xa khi Zoya đồng ý kết hôn với Arshad do hiểu lầm Aditya là người xấu. Một lần nữa, Aditya gặp phải khó khăn để giành lại hạnh phúc cho mình… Bộ phim đã đoạt được “Phim truyền hình hay nhất” tại giải Truyền Hình Hàn Lâm Ấn Độ (ITAA) năm 2018. Harshad Chopda được giải nam diễn viên được yêu thích nhất tại IATT năm 2018 và Jennifer Winget được giải nữ diễn viên xuất sắc nhất tại Golden Awards 2018 cùng với nhiều giải thưởng khác tại Lion Awards, AVTA, ITA Awards…</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2026-03-31T06:53:54.589+00:00","_from_supabase":true,"tmdb_id":null,"_supabaseOriginalSlug":"ngay-moi-bat-dau","_supabaseExportEpisodesOnly":false,"_image_preserved":true}];